    /**
     * @method
     * @name htx#fetchTime
     * @description fetches the current integer timestamp in milliseconds from the exchange server
     * @see https://huobiapi.github.io/docs/spot/v1/en/#get-current-timestamp
     * @see https://huobiapi.github.io/docs/coin_margined_swap/v1/en/#get-current-system-timestamp
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int} the current integer timestamp in milliseconds from the exchange server
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTime(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object options = this.safeValue(this.options, "fetchTime", new java.util.HashMap<String, Object>() {{}});
            Object defaultType = this.safeString(this.options, "defaultType", "spot");
            Object type = this.safeString(options, "type", defaultType);
            type = this.safeString(parameters, "type", type);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "future"))) || Helpers.isTrue((Helpers.isEqual(type, "swap")))))
            {
                response = (this.contractPublicGetApiV1Timestamp(parameters)).join();
            } else
            {
                response = (this.spotPublicGetV1CommonTimestamp(parameters)).join();
            }
            //
            // spot
            //
            //     {"status":"ok","data":1637504261099}
            //
            // future, swap
            //
            //     {"status":"ok","ts":1637504164707}
            //
            return this.safeInteger2(response, "data", "ts");
        });

    }

    public Object parseTradingFee(Object fee, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol":"btcusdt",
        //         "actualMakerRate":"0.002",
        //         "actualTakerRate":"0.002",
        //         "takerFeeRate":"0.002",
        //         "makerFeeRate":"0.002"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(fee, "symbol");
        return new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "symbol", HtxCore.this.safeSymbol(marketId, market) );
            put( "maker", HtxCore.this.safeNumber(fee, "actualMakerRate") );
            put( "taker", HtxCore.this.safeNumber(fee, "actualTakerRate") );
            put( "percentage", null );
            put( "tierBased", null );
        }};
    }

