            //                 "init-nav":10.000000000000000000,
            //                 "api-trading":"enabled",
            //                 "tags":"etp,nav,holdinglimit"
            //             },
            //         ]
            //     }
            //
            // inverse (swap & future)
            //
            //     {
            //         "status":"ok",
            //         "data":[
            //             {
            //                 "symbol":"BTC",
            //                 "contract_code":"BTC211126", /// BTC-USD in swap
            //                 "contract_type":"this_week", // only in future
