            //                 "settlement_date":"16xxxxxxxxxxx" // only in swap
            //             },
            //           ...
            //         ],
            //         "ts":1637474595140
            //     }
            //
            // linear (swap & future)
            //
            //     {
            //         "status":"ok",
            //         "data":[
            //             {
            //                 "symbol":"BTC",
            //                 "contract_code":"BTC-USDT-211231", // or "BTC-USDT" in swap
            //                 "contract_size":0.001,
            //                 "price_tick":0.1,
