    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //     {
        //         "id": "75115912",
        //         "type": "deposit",
        //         "sub-type": "NORMAL",
        //         "request-id": "trc20usdt-a2e229a44ef2a948c874366230bb56aa73631cc0a03d177bd8b4c9d38262d7ff-200",
        //         "currency": "usdt",
        //         "chain": "trc20usdt",
        //         "tx-hash": "a2e229a44ef2a948c874366230bb56aa73631cc0a03d177bd8b4c9d38262d7ff",
        //         "amount": "2849.000000000000000000",
        //         "from-addr-tag": "",
        //         "address-id": "0",
        //         "address": "TRFTd1FxepQE6CnpwzUEMEbFaLm5bJK67s",
        //         "address-tag": "",
        //         "fee": "0",
        //         "state": "safe",
        //         "wallet-confirm": "2",
        //         "created-at": "1621843808662",
        //         "updated-at": "1621843857137"
        //     },
        //
        // fetchWithdrawals
        //
        //     {
        //         "id": "61335312",
        //         "type": "withdraw",
        //         "sub-type": "NORMAL",
        //         "currency": "usdt",
        //         "chain": "trc20usdt",
        //         "tx-hash": "30a3111f2fead74fae45c6218ca3150fc33cab2aa59cfe41526b96aae79ce4ec",
        //         "amount": "12.000000000000000000",
        //         "from-addr-tag": "",
        //         "address-id": "27321591",
        //         "address": "TRf5JacJQRsF4Nm2zu11W6maDGeiEWQu9e",
        //         "address-tag": "",
        //         "fee": "1.000000000000000000",
        //         "state": "confirmed",
        //         "created-at": "1621852316553",
        //         "updated-at": "1621852467041"
        //     }
        //
        // withdraw
        //
        //     {
        //         "status": "ok",
        //         "data": "99562054"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transaction, "created-at");
        Object code = this.safeCurrencyCode(this.safeString(transaction, "currency"));
        Object type = this.safeString(transaction, "type");
        if (Helpers.isTrue(Helpers.isEqual(type, "withdraw")))
        {
            type = "withdrawal";
        }
        Object feeCost = this.safeString(transaction, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            feeCost = Precise.stringAbs(feeCost);
        }
        Object networkId = this.safeString(transaction, "chain");
        Object txHash = this.safeString(transaction, "tx-hash");
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(networkId, "ETH")) && Helpers.isTrue(Helpers.isLessThan(Helpers.getIndexOf(txHash, "0x"), 0))))
        {
            txHash = Helpers.add("0x", txHash);
        }
        Object subType = this.safeString(transaction, "sub-type");
        Object intern = Helpers.isEqual(subType, "FAST");
        final Object finalTxHash = txHash;
        final Object finalNetworkId = networkId;
        final Object finalType = type;
        final Object finalFeeCost = feeCost;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", HtxCore.this.safeString2(transaction, "id", "data") );
            put( "txid", finalTxHash );
            put( "timestamp", timestamp );
            put( "datetime", HtxCore.this.iso8601(timestamp) );
            put( "network", HtxCore.this.networkIdToCode(finalNetworkId, code) );
            put( "address", HtxCore.this.safeString(transaction, "address") );
            put( "addressTo", null );
            put( "addressFrom", null );
            put( "tag", HtxCore.this.safeString(transaction, "address-tag") );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", HtxCore.this.safeNumber(transaction, "amount") );
            put( "currency", code );
            put( "status", HtxCore.this.parseTransactionStatus(HtxCore.this.safeString(transaction, "state")) );
            put( "updated", HtxCore.this.safeInteger(transaction, "updated-at") );
            put( "comment", null );
            put( "internal", intern );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", HtxCore.this.parseNumber(finalFeeCost) );
                put( "rate", null );
            }} );
        }};
    }

    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "unknown", "failed" );
            put( "confirming", "pending" );
            put( "confirmed", "ok" );
            put( "safe", "ok" );
            put( "orphan", "failed" );
            put( "submitted", "pending" );
            put( "canceled", "canceled" );
            put( "reexamine", "pending" );
            put( "reject", "failed" );
            put( "pass", "pending" );
            put( "wallet-reject", "failed" );
            put( "confirm-error", "failed" );
            put( "repealed", "failed" );
            put( "wallet-transfer", "pending" );
            put( "pre-transfer", "pending" );
            put( "verifying", "pending" );
        }};
        return this.safeString(statuses, status, status);
    }

    /**
     * @method
     * @name htx#withdraw
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=7ec4cc41-7773-11ed-9966-0242ac110003
     * @description make a withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount2, Object address, Object... optionalArgs)
    {
        final Object amount3 = amount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object amount = amount3;
            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            (this.loadMarkets()).join();
            this.checkAddress(address);
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "address", address );
                put( "currency", ((String)Helpers.GetValue(currency, "id")).toLowerCase() );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "addr-tag", tag); // only for XRP?
            }
            Object networkCode = null;
            var networkCodeparametersVariable = this.handleNetworkCodeAndParams(parameters);
            networkCode = ((java.util.List<Object>) networkCodeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) networkCodeparametersVariable).get(1);
            if (Helpers.isTrue(!Helpers.isEqual(networkCode, null)))
            {
                Helpers.addElementToObject(request, "chain", this.networkCodeToId(networkCode, code));
            }
            amount = Helpers.parseFloat(this.currencyToPrecision(code, amount, networkCode));
            Object withdrawOptions = this.safeValue(this.options, "withdraw", new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(this.safeBool(withdrawOptions, "includeFee", false)))
            {
                Object fee = this.safeNumber(parameters, "fee");
                if (Helpers.isTrue(Helpers.isEqual(fee, null)))
                {
                    Object currencies = (this.fetchCurrenciesAsync()).join();
                    this.currencies = this.mapToSafeMap(this.deepExtend(this.currencies, currencies));
                    Object targetNetwork = this.safeValue(Helpers.GetValue(currency, "networks"), networkCode, new java.util.HashMap<String, Object>() {{}});
                    fee = this.safeNumber(targetNetwork, "fee");
                    if (Helpers.isTrue(Helpers.isEqual(fee, null)))
                    {
                        throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw() function can not find withdraw fee for chosen network. You need to re-load markets with \"exchange.loadMarkets(true)\", or provide the \"fee\" parameter")) ;
                    }
                }
                // fee needs to be deducted from whole amount
                Object feeString = this.currencyToPrecision(code, fee, networkCode);
                parameters = this.omit(parameters, "fee");
                Object amountString = this.numberToString(amount);
                Object amountSubtractedString = Precise.stringSub(amountString, feeString);
                Object amountSubtracted = Helpers.parseFloat(amountSubtractedString);
                Helpers.addElementToObject(request, "fee", Helpers.parseFloat(feeString));
                amount = Helpers.parseFloat(this.currencyToPrecision(code, amountSubtracted, networkCode));
            }
            Helpers.addElementToObject(request, "amount", amount);
            Object response = (this.spotPrivatePostV1DwWithdrawApiCreate(this.extend(request, parameters))).join();
            //
            //     {
            //         "status": "ok",
            //         "data": "99562054"
            //     }
            //
            return this.parseTransaction(response, currency);
        });

    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        // transfer
        //
        //     {
        //         "data": 12345,
        //         "status": "ok"
        //     }
        //
        // fetchTransfers
        //
        //     {
        //         "id": 12345,
        //         "transfer_id": "12345",
        //         "amount": "10",
        //         "currency": "USDT",
        //         "status": "success",
        //         "from_account_type": "spot",
        //         "to_account_type": "margin",
        //         "from_asset_type": "",
        //         "to_asset_type": "ETHUSDT",
        //         "transfer_time": 1770357494000
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object accountsById = this.safeDict(this.options, "accountsById", new java.util.HashMap<String, Object>() {{}});
        Object id = this.safeString2(transfer, "transfer_id", "data");
        Object currencyId = this.safeString(transfer, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object amount = this.safeNumber(transfer, "amount");
        Object timestamp = this.safeInteger(transfer, "transfer_time");
        Object fromAccountRaw = this.safeString(transfer, "from_account_type");
        Object toAccountRaw = this.safeString(transfer, "to_account_type");
        Object fromAccount = this.safeString(accountsById, fromAccountRaw, fromAccountRaw);
        Object toAccount = this.safeString(accountsById, toAccountRaw, toAccountRaw);
        Object statusRaw = this.safeString(transfer, "status");
        Object status = null;
        if (Helpers.isTrue(Helpers.isEqual(statusRaw, "success")))
        {
            status = "ok";
        } else if (Helpers.isTrue(Helpers.isEqual(statusRaw, "pending")))
        {
            status = "pending";
        } else if (Helpers.isTrue(Helpers.isEqual(statusRaw, "failed")))
        {
            status = "failed";
        }
        final Object finalStatus = status;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", id );
            put( "timestamp", timestamp );
            put( "datetime", HtxCore.this.iso8601(timestamp) );
            put( "currency", code );
            put( "amount", amount );
            put( "fromAccount", fromAccount );
            put( "toAccount", toAccount );
            put( "status", finalStatus );
        }};
    }

    /**
     * @method
     * @name htx#transfer
     * @description transfer currency internally between wallets on the same account
     * @see https://huobiapi.github.io/docs/dm/v1/en/#transfer-margin-between-spot-account-and-future-account
     * @see https://huobiapi.github.io/docs/spot/v1/en/#transfer-fund-between-spot-account-and-future-contract-account
     * @see https://huobiapi.github.io/docs/usdt_swap/v1/en/#general-transfer-margin-between-spot-account-and-usdt-margined-contracts-account
     * @see https://huobiapi.github.io/docs/spot/v1/en/#transfer-asset-from-spot-trading-account-to-cross-margin-account-cross
     * @see https://huobiapi.github.io/docs/spot/v1/en/#transfer-asset-from-spot-trading-account-to-isolated-margin-account-isolated
     * @see https://huobiapi.github.io/docs/spot/v1/en/#transfer-asset-from-cross-margin-account-to-spot-trading-account-cross
     * @see https://huobiapi.github.io/docs/spot/v1/en/#transfer-asset-from-isolated-margin-account-to-spot-trading-account-isolated
     * @param {string} code unified currency code
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from 'spot', 'future', 'swap'
     * @param {string} toAccount account to transfer to 'spot', 'future', 'swap'
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.symbol] used for isolated margin transfer
     * @param {string} [params.subType] 'linear' or 'inverse', only used when transfering to/from swap accounts
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount2, Object toAccount, Object... optionalArgs)
    {
        final Object fromAccount3 = fromAccount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object fromAccount = fromAccount3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency", Helpers.GetValue(currency, "id") );
                put( "amount", Helpers.parseFloat(HtxCore.this.currencyToPrecision(code, amount)) );
            }};
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("transfer", null, parameters);
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object fromAccountId = this.convertTypeToAccount(fromAccount);
            Object toAccountId = this.convertTypeToAccount(toAccount);
            Object toCross = Helpers.isEqual(toAccountId, "cross");
            Object fromCross = Helpers.isEqual(fromAccountId, "cross");
            Object toIsolated = this.inArray(toAccountId, this.ids);
            Object fromIsolated = this.inArray(fromAccountId, this.ids);
            Object fromSpot = Helpers.isEqual(fromAccountId, "pro");
            Object toSpot = Helpers.isEqual(toAccountId, "pro");
            if (Helpers.isTrue(Helpers.isTrue(fromSpot) && Helpers.isTrue(toSpot)))
            {
                throw new BadRequest((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " transfer () cannot make a transfer between "), fromAccount), " and "), toAccount)) ;
            }
            Object fromOrToFuturesAccount = Helpers.isTrue((Helpers.isEqual(fromAccountId, "futures"))) || Helpers.isTrue((Helpers.isEqual(toAccountId, "futures")));
            Object response = null;
            if (Helpers.isTrue(fromOrToFuturesAccount))
            {
                Object type = Helpers.add(Helpers.add(fromAccountId, "-to-"), toAccountId);
                type = this.safeString(parameters, "type", type);
                Helpers.addElementToObject(request, "type", type);
                response = (this.spotPrivatePostV1FuturesTransfer(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(fromSpot) && Helpers.isTrue(toCross)))
            {
                response = (this.privatePostCrossMarginTransferIn(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(fromCross) && Helpers.isTrue(toSpot)))
            {
                response = (this.privatePostCrossMarginTransferOut(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(fromSpot) && Helpers.isTrue(toIsolated)))
            {
                Helpers.addElementToObject(request, "symbol", toAccountId);
                response = (this.privatePostDwTransferInMargin(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isTrue(fromIsolated) && Helpers.isTrue(toSpot)))
            {
                Helpers.addElementToObject(request, "symbol", fromAccountId);
                response = (this.privatePostDwTransferOutMargin(this.extend(request, parameters))).join();
            } else
            {
                if (Helpers.isTrue(Helpers.isEqual(subType, "linear")))
                {
                    if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(fromAccountId, "swap"))) || Helpers.isTrue((Helpers.isEqual(fromAccount, "linear-swap")))))
                    {
                        fromAccountId = "linear-swap";
                    } else
                    {
                        toAccountId = "linear-swap";
                    }
                    // check if cross-margin or isolated
                    Object symbol = this.safeString(parameters, "symbol");
                    parameters = this.omit(parameters, "symbol");
                    if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                    {
                        symbol = this.marketId(symbol);
                        Helpers.addElementToObject(request, "margin-account", symbol);
                    } else
                    {
                        Helpers.addElementToObject(request, "margin-account", "USDT"); // cross-margin
                    }
                }
                Helpers.addElementToObject(request, "from", ((Helpers.isTrue(fromSpot))) ? "spot" : fromAccountId);
                Helpers.addElementToObject(request, "to", ((Helpers.isTrue(toSpot))) ? "spot" : toAccountId);
                response = (this.v2PrivatePostAccountTransfer(this.extend(request, parameters))).join();
            }
            //
            //    {
            //        "code": "200",
            //        "data": "660150061",
            //        "message": "Succeed",
            //        "success": true,
            //        "print-log": true
            //    }
            //
            return this.parseTransfer(response, currency);
        });

    }

