    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        // inverse swap
        //
        //     {
        //         "estimated_rate": null,
        //         "funding_rate": "0.000100000000000000",
        //         "contract_code": "BTC-USD",
        //         "symbol": "BTC",
        //         "fee_asset": "BTC",
        //         "funding_time": "1781280000000",
        //         "next_funding_time": null
        //     }
        //
        // linear swap
        //
        //     {
        //         "contract_code": "BTC-USDT",
        //         "funding_rate": "0.000083024939363172",
        //         "funding_time": "1781251200000",
        //         "next_funding_time": "1781280000000",
        //         "min_funding_rate": "-0.003750000000000000",
        //         "max_funding_rate": "0.003750000000000000"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object nextFundingRate = this.safeNumber(contract, "estimated_rate");
        Object fundingTimestamp = this.safeInteger(contract, "funding_time");
        Object nextFundingTimestamp = this.safeInteger(contract, "next_funding_time");
        Object fundingTimeString = this.safeString(contract, "funding_time");
        Object nextFundingTimeString = this.safeString(contract, "next_funding_time");
        Object millisecondsInterval = Precise.stringSub(nextFundingTimeString, fundingTimeString);
        Object marketId = this.safeString(contract, "contract_code");
        Object symbol = this.safeSymbol(marketId, market);
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", symbol );
            put( "markPrice", null );
            put( "indexPrice", null );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", HtxCore.this.safeNumber(contract, "funding_rate") );
            put( "fundingTimestamp", fundingTimestamp );
            put( "fundingDatetime", HtxCore.this.iso8601(fundingTimestamp) );
            put( "nextFundingRate", nextFundingRate );
            put( "nextFundingTimestamp", nextFundingTimestamp );
            put( "nextFundingDatetime", HtxCore.this.iso8601(nextFundingTimestamp) );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", HtxCore.this.parseFundingInterval(millisecondsInterval) );
        }};
    }

