            put( "fee-deduction", "fee" );
            put( "transfer", "transfer" );
            put( "credit", "credit" );
            put( "liquidation", "trade" );
            put( "interest", "credit" );
            put( "deposit", "deposit" );
            put( "withdraw", "withdrawal" );
            put( "withdraw-fee", "fee" );
