            //                    "amount_type": "2",
            //                    "ts": "1648220400000",
            //                    "value": "194059884.1850000000000000"
            //                },
            //                ...
            //            ],
            //            "contract_code": "BTC-USDT",
            //            "business_type": "swap",
            //            "pair": "BTC-USDT",
            //            "contract_type": "swap",
            //            "trade_partition": "USDT"
            //        },
            //        "ts": "1648223733007"
            //    }
            //
            //  contractPublicGetSwapApiV1SwapHisOpenInterest
            //    {
            //        "status": "ok",
            //        "data": {
            //            "symbol": "CRV",
            //            "tick": [
            //                {
            //                    "volume": 19174.0000000000000000,
            //                    "amount_type": 1,
            //                    "ts": 1648224000000
            //                },
            //                ...
            //            ],
            //            "contract_code": "CRV-USD"
            //        },
            //        "ts": 1648226554260
            //    }
            //
            //  contractPublicGetApiV1ContractHisOpenInterest
            //    {
            //         "status": "ok",
            //         "data": {
            //             "symbol": "BTC",
            //             "contract_type": "this_week",
            //             "tick": [
            //                {
            //                     "volume": "48419.0000000000000000",
            //                     "amount_type": 1,
            //                     "ts": 1648224000000
            //                },
