    /**
     * @method
     * @name htx#fetchOpenInterests
     * @description Retrieves the open interest for a list of symbols
     * @see https://huobiapi.github.io/docs/dm/v1/en/#get-contract-open-interest-information
     * @see https://huobiapi.github.io/docs/coin_margined_swap/v1/en/#get-swap-open-interest-information
     * @param {string[]} [symbols] a list of unified CCXT market symbols
     * @param {object} [params] exchange specific parameters
     * @returns {object[]} a list of [open interest structures]{@link https://docs.ccxt.com/?id=open-interest-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOpenInterests(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            symbols = this.marketSymbols(symbols);
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbols, null)))
            {
                Object symbolsLength = Helpers.getArrayLength(symbols);
                if (Helpers.isTrue(Helpers.isGreaterThan(symbolsLength, 0)))
                {
                    Object first = this.safeString(symbols, 0);
                    market = this.market(first);
                }
            }
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("fetchOpenInterests", market, parameters, "linear");
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object marketType = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchOpenInterests", market, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(marketType, "future")))
            {
                response = (this.contractPublicGetApiV1ContractOpenInterest(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(subType, "inverse")))
            {
                response = (this.contractPublicGetSwapApiV1SwapOpenInterest(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchOpenInterests() does not currently support linear markets")) ;
            }
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOpenInterests(data, symbols);
        });

    }

    /**
     * @method
     * @name htx#fetchOpenInterest
     * @description Retrieves the open interest of a currency
     * @see https://huobiapi.github.io/docs/dm/v1/en/#get-contract-open-interest-information
     * @see https://huobiapi.github.io/docs/coin_margined_swap/v1/en/#get-swap-open-interest-information
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=8cb89359-77b5-11ed-9966-19b97fb53f2
     * @param {string} symbol Unified CCXT market symbol
     * @param {object} [params] exchange specific parameters
     * @returns {object} an open interest structure{@link https://docs.ccxt.com/?id=open-interest-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOpenInterest(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            if (!Helpers.isTrue(Helpers.GetValue(market, "contract")))
            {
                throw new BadRequest((String)Helpers.add(this.id, " fetchOpenInterest() supports contract markets only")) ;
            }
            if (Helpers.isTrue(Helpers.GetValue(market, "option")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " fetchOpenInterest() does not currently support option markets")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "contract_code", Helpers.GetValue(market, "id") );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "future")))
            {
                Helpers.addElementToObject(request, "contract_type", this.safeString(Helpers.GetValue(market, "info"), "contract_type"));
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "baseId"));
                // COIN-M futures
                response = (this.contractPublicGetApiV1ContractOpenInterest(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                // USDT-M swaps
                response = (this.contractPublicGetV5MarketOpenInterest(this.extend(request, parameters))).join();
            } else
            {
                // COIN-M swaps
                response = (this.contractPublicGetSwapApiV1SwapOpenInterest(this.extend(request, parameters))).join();
            }
            //
            // USDT-M linear swap
            //
            //     {
            //         "code": 200,
            //         "message": "Success",
            //         "data": {
            //             "amount": "32476.092",
            //             "volume": "32476092",
            //             "value": "2063137924.9668",
            //             "contract_code": "BTC-USDT",
            //             "trade_amount": "11371.362",
            //             "trade_volume": "11371362",
            //             "trade_turnover": "723600792.7222"
            //         },
            //         "ts": 1781327941440
            //     }
            //
            // COIN-M Swap contractPublicGetSwapApiV1SwapOpenInterest
            //
            //     {
            //         "status": "ok",
            //         "data": [
            //             {
            //                 "volume": 518018.000000000000000000,
            //                 "amount": 2769.675777407074725180,
            //                 "symbol": "BTC",
            //                 "contract_code": "BTC-USD",
            //                 "trade_amount": 9544.4032080046491323463688602729806842458,
            //                 "trade_volume": 1848448,
            //                 "trade_turnover": 184844800.000000000000000000
            //             }
            //         ],
            //         "ts": 1664337226028
            //     }
            //
            // COIN-M Futures contractPublicGetApiV1ContractOpenInterest
            //
            //     {
            //         "status": "ok",
            //         "data": [
            //             {
            //                 "volume": 118850.000000000000000000,
            //                 "amount": 635.502025211544374189,
            //                 "symbol": "BTC",
            //                 "contract_type": "this_week",
            //                 "contract_code": "BTC220930",
            //                 "trade_amount": 1470.9400749347598691119206024033947897351,
            //                 "trade_volume": 286286,
            //                 "trade_turnover": 28628600.000000000000000000
            //             }
            //         ],
            //         "ts": 1664337928805
            //     }
            //
            Object timestamp = this.safeInteger(response, "ts");
            if (Helpers.isTrue(Helpers.GetValue(market, "linear")))
            {
                Object result = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
                return this.extend(this.parseOpenInterest(result, market), new java.util.HashMap<String, Object>() {{
                    put( "timestamp", timestamp );
                    put( "datetime", HtxCore.this.iso8601(timestamp) );
                }});
            }
            Object data = this.safeValue(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object openInterest = this.parseOpenInterest(Helpers.GetValue(data, 0), market);
            Helpers.addElementToObject(openInterest, "timestamp", timestamp);
            Helpers.addElementToObject(openInterest, "datetime", this.iso8601(timestamp));
            return openInterest;
        });

    }

    public Object parseOpenInterest(Object interest, Object... optionalArgs)
    {
        //
        // fetchOpenInterestHistory
        //
        //    {
        //        "volume": "4385.4350000000000000",
        //        "amount_type": "2",
        //        "ts": "1648220400000",
        //        "value": "194059884.1850000000000000"
        //    }
        //
        // fetchOpenInterest: USDT-M
        //
        //     {
        //         "amount": "32476.092",
        //         "volume": "32476092",
        //         "value": "2063137924.9668",
        //         "contract_code": "BTC-USDT",
        //         "trade_amount": "11371.362",
        //         "trade_volume": "11371362",
        //         "trade_turnover": "723600792.7222"
        //     }
        //
        // fetchOpenInterest: COIN-M Swap
        //
        //     {
        //         "volume": 518018.000000000000000000,
        //         "amount": 2769.675777407074725180,
        //         "symbol": "BTC",
        //         "contract_code": "BTC-USD",
        //         "trade_amount": 9544.4032080046491323463688602729806842458,
        //         "trade_volume": 1848448,
        //         "trade_turnover": 184844800.000000000000000000
        //     }
        //
        // fetchOpenInterest: COIN-M Futures
        //
        //     {
        //         "volume": 118850.000000000000000000,
        //         "amount": 635.502025211544374189,
        //         "symbol": "BTC",
        //         "contract_type": "this_week",
        //         "contract_code": "BTC220930",
        //         "trade_amount": 1470.9400749347598691119206024033947897351,
        //         "trade_volume": 286286,
        //         "trade_turnover": 28628600.000000000000000000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(interest, "ts");
        Object amount = this.safeNumber(interest, "volume");
        Object value = this.safeNumber(interest, "value");
        Object marketId = this.safeString(interest, "contract_code");
        return this.safeOpenInterest(new java.util.HashMap<String, Object>() {{
            put( "symbol", HtxCore.this.safeSymbol(marketId, market) );
            put( "baseVolume", amount );
            put( "quoteVolume", value );
            put( "openInterestAmount", amount );
            put( "openInterestValue", value );
            put( "timestamp", timestamp );
            put( "datetime", HtxCore.this.iso8601(timestamp) );
            put( "info", interest );
        }}, market);
    }

